 1	import type { FC } from 'react';
 2	import { Controller, useFormContext } from 'react-hook-form';
 3	
 4	import { HelpIconPopover } from '@components/common/HelpIconPopover/HelpIconPopover';
 5	import Select from '@components/common/Select';
 6	import { type IoK8sApiCoreV1Secret, SecretModel, type V1beta1Provider } from '@kubev2v/types';
 7	import {
 8	  getGroupVersionKindForModel,
 9	  useK8sWatchResource,
10	} from '@openshift-console/dynamic-plugin-sdk';
11	import { FormGroup, SelectList, SelectOption, Stack, StackItem } from '@patternfly/react-core';
12	import { getName, getNamespace, getUID } from '@utils/crds/common/selectors';
13	import { isEmpty } from '@utils/helpers';
14	import { useForkliftTranslation } from '@utils/i18n';
15	
16	import { StorageMapFieldId, storageMapFieldLabels } from '../../constants';
17	
18	type StorageSecretFieldProps = {
19	  fieldId: string;
20	  sourceProvider: V1beta1Provider | undefined;
21	};
22	
23	const StorageSecretField: FC<StorageSecretFieldProps> = ({ fieldId, sourceProvider }) => {
24	  const { t } = useForkliftTranslation();
25	  const {
26	    control,
27	    formState: { isSubmitting },
28	  } = useFormContext();
29	
30	  const [secrets] = useK8sWatchResource<IoK8sApiCoreV1Secret[]>({
31	    groupVersionKind: getGroupVersionKindForModel(SecretModel),
32	    isList: true,
33	    namespace: getNamespace(sourceProvider),
34	    namespaced: true,
35	  });
36	
37	  return (
38	    <FormGroup
39	      fieldId={fieldId}
40	      label={storageMapFieldLabels[StorageMapFieldId.StorageSecret]}
41	      labelHelp={
42	        <HelpIconPopover>
43	          <Stack hasGutter>
44	            <StackItem>
45	              {t(
46	                "Holds the authentication credentials for your storage provider, allowing the offload plugin to securely connect to and control your storage hardware's API (for example, Hitachi Vantara or NetApp ONTAP).",
47	              )}
48	            </StackItem>
49	            <StackItem>
50	              {t(
51	                'This secret must be created in your project beforehand, typically using details provided by your storage administrator.',
52	              )}
53	            </StackItem>
54	          </Stack>
55	        </HelpIconPopover>
56	      }
57	    >
58	      <Controller
59	        name={fieldId}
60	        control={control}
61	        render={({ field }) => (
62	          <Select
63	            ref={field.ref}
64	            id={fieldId}
65	            isDisabled={isSubmitting}
66	            value={field.value}
67	            onSelect={(_e, value) => {
68	              field.onChange(value);
69	            }}
70	            placeholder={t('Select storage secret')}
71	          >
72	            <SelectList>
73	              {isEmpty(secrets) ? (
74	                <SelectOption key="empty" isDisabled>
75	                  {t('No secrets available for this provider')}
76	                </SelectOption>
77	              ) : (
78	                secrets.map((secret) => {
79	                  const secretName = getName(secret);
80	
81	                  return (
82	                    <SelectOption key={getUID(secret)} value={secretName}>
83	                      {secretName}
84	                    </SelectOption>
85	                  );
86	                })
87	              )}
88	            </SelectList>
89	          </Select>
90	        )}
91	      />
92	    </FormGroup>
93	  );
94	};
95	
96	export default StorageSecretField;

